+// stepIDs returns the IDs of all steps in a formula for test diagnostics.
+func stepIDs(f *Formula) []string {
+	ids := make([]string, len(f.Steps))
+	for i, s := range f.Steps {
+		ids[i] = s.ID
+	}
+	return ids
+}
